-- armory_patch_reduced.sql
-- Reduced/idempotent armory patch for the vanilla base dump in SPP-core.
-- Generated from armory_patch.sql against SPP-core\SPP_Server\sql\vanilla\armory.sql.
--
-- Changes from the original bundle:
--   - Keeps only the dbc_spellicon delta versus the base armory.sql dump.
--   - Keeps tooltip schema/data only where the base dump is missing columns.
--   - Omits the dbc_spell effect_die_sides patch because the base dump already contains it.
--   - Makes armory_itemset_notes idempotent instead of dropping/recreating it.


-- armory_itemset_notes
-- ========================================================
-- ========================================================

-- ========================================================
-- 68_armory_itemset_notes.sql
-- Adds a curated metadata table for item-set blurbs/notes.
--
-- Run against each armory database that serves dbc_itemset.
-- This table is intentionally separate from dbc_itemset so:
--   - dbc_itemset stays the canonical source for set identity
--   - curated site notes can evolve without editing DBC imports
--   - section/class presentation can be maintained explicitly
-- ========================================================

CREATE TABLE IF NOT EXISTS `armory_itemset_notes` (
  `id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `set_id` INT UNSIGNED NOT NULL,
  `set_name` VARCHAR(150) NOT NULL DEFAULT '',
  `section` ENUM('misc','world','pvp') NOT NULL DEFAULT 'misc',
  `class_name` VARCHAR(32) NULL DEFAULT NULL,
  `note_title` VARCHAR(255) NOT NULL DEFAULT '',
  `note_body` MEDIUMTEXT NOT NULL,
  `piece_count` SMALLINT UNSIGNED NOT NULL DEFAULT 0,
  `source_key` VARCHAR(64) NULL DEFAULT NULL,
  `sort_order` INT UNSIGNED NOT NULL DEFAULT 0,
  `is_active` TINYINT(1) UNSIGNED NOT NULL DEFAULT 1,
  `created_at` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_itemset_note_scope` (`set_id`, `section`, `class_name`),
  KEY `idx_itemset_section_class` (`section`, `class_name`),
  KEY `idx_itemset_name` (`set_name`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Seeded from the legacy _sets_class/_sets_world/_sets_pvp PHP blurb arrays.
-- Only rows that resolved to a real dbc_itemset.id at generation time were included.
-- Reachable armory schemas during generation: tbcarmory, classicarmory

