  (533, 'Battlegear of Undead Slaying', 'world', 'Paladin', 'Battlegear of Undead Slaying', 'Scourge Invasion plate set with strong bonuses vs undead. Used by <b>Warriors</b> and <b>Paladins</b>.', 4, 'WD_PlateUndead', 1320, 1),
  (533, 'Battlegear of Undead Slaying', 'world', 'Warrior', 'Battlegear of Undead Slaying', 'Scourge Invasion plate set with strong bonuses vs undead. Used by <b>Warriors</b> and <b>Paladins</b>.', 4, 'WD_PlateUndead', 1310, 1),
  (535, 'Garb of the Undead Slayer', 'world', 'Hunter', 'Garb of the Undead Slayer', 'Mail variant of the Scourge Invasion event sets. Boosted damage against undead, a solid temporary gearing option.', 4, 'WD_MailUndead', 1280, 1),
  (535, 'Garb of the Undead Slayer', 'world', 'Shaman', 'Garb of the Undead Slayer', 'Mail variant of the Scourge Invasion event sets. Boosted damage against undead, a solid temporary gearing option.', 4, 'WD_MailUndead', 1290, 1),
  (536, 'Regalia of Undead Cleansing', 'world', 'Mage', 'Regalia of Undead Cleansing', 'Scourge Invasion event set tailored against undead foes. Used by <b>Mages</b>, <b>Warlocks</b>, and <b>Priests</b>.', 4, 'WD_UndeadCleansing', 1150, 1),
  (536, 'Regalia of Undead Cleansing', 'world', 'Priest', 'Regalia of Undead Cleansing', 'Scourge Invasion event set tailored against undead foes. Used by <b>Mages</b>, <b>Warlocks</b>, and <b>Priests</b>.', 4, 'WD_UndeadCleansing', 1160, 1),
  (536, 'Regalia of Undead Cleansing', 'world', 'Warlock', 'Regalia of Undead Cleansing', 'Scourge Invasion event set tailored against undead foes. Used by <b>Mages</b>, <b>Warlocks</b>, and <b>Priests</b>.', 4, 'WD_UndeadCleansing', 1170, 1),
  (620, 'Assassination Armor', 'misc', 'Rogue', 'Dungeon Set 3', 'Burning Crusade\'s Dungeon Set 3 bridged the gap between leveling gear and Tier 4 raids. Unlike earlier dungeon sets, DS3 came in multiple variants per armor type, catering to casters, healers, melee DPS, and tanks. Players farmed heroic dungeons across Outland for these five-piece sets, earning powerful bonuses and distinct looks. Mana-Etched Regalia empowered spellcasters, Beast Lord Armor defined early hunter identity, and Doomplate Battlegear gave tanks their first taste of Outland survivability. DS3 sets were often a player\'s first step into Karazhan attunement and the raid circuit of Outland. <span class=\'set-note\'>(TBC launch / Patch 2.0)</span>', 5, 'DS3', 1040, 1),
  (621, 'Netherblade', 'misc', 'Rogue', 'Tier 4', 'Tier 4 represented the first raid tier of Burning Crusade, spread across three entry raids: Karazhan, Gruul\'s Lair, and Magtheridon\'s Lair. Unlike Classic, loot dropped as tokens-Champion, Hero, and Defender-that were redeemed in Shattrath for class sets. These sets split into different versions for each spec (Raiment, Armor, Battlegear, Regalia), marking the beginning of Blizzard\'s design philosophy of tailoring raid gear to multiple class roles. <span class=\'set-note\'>(TBC launch)</span>', 5, 'T4', 780, 1),
  (622, 'Deathmantle', 'misc', 'Rogue', 'Tier 5', 'Tier 5 came from Serpentshrine Cavern and The Eye, where Lady Vashj and Kael\'thas guarded the attunement keys to Mount Hyjal and Black Temple. These sets marked a player\'s entry into serious raiding progression, and clearing both raids was among the most difficult pre-nerf challenges of WoW. The visuals reflected Outland\'s arcane and aquatic motifs, with standout appearances like the Mage\'s Tirisfal Regalia and the Priest\'s Avatar Raiment. <span class=\'set-note\'>(Available early; retuned in Patch 2.1)</span>', 5, 'T5', 870, 1),
  (623, 'Righteous Armor', 'misc', 'Paladin', 'Dungeon Set 3', 'Burning Crusade\'s Dungeon Set 3 bridged the gap between leveling gear and Tier 4 raids. Unlike earlier dungeon sets, DS3 came in multiple variants per armor type, catering to casters, healers, melee DPS, and tanks. Players farmed heroic dungeons across Outland for these five-piece sets, earning powerful bonuses and distinct looks. Mana-Etched Regalia empowered spellcasters, Beast Lord Armor defined early hunter identity, and Doomplate Battlegear gave tanks their first taste of Outland survivability. DS3 sets were often a player\'s first step into Karazhan attunement and the raid circuit of Outland. <span class=\'set-note\'>(TBC launch / Patch 2.0)</span>', 5, 'DS3', 1070, 1),
  (624, 'Justicar Raiment', 'misc', 'Paladin', 'Tier 4', 'Tier 4 represented the first raid tier of Burning Crusade, spread across three entry raids: Karazhan, Gruul\'s Lair, and Magtheridon\'s Lair. Unlike Classic, loot dropped as tokens-Champion, Hero, and Defender-that were redeemed in Shattrath for class sets. These sets split into different versions for each spec (Raiment, Armor, Battlegear, Regalia), marking the beginning of Blizzard\'s design philosophy of tailoring raid gear to multiple class roles. <span class=\'set-note\'>(TBC launch)</span>', 5, 'T4', 760, 1),
