  (717, 'Field Marshal\'s Earthshaker', 'pvp', 'Shaman', 'Rank 13 - Field Marshal / Warlord', 'The apex of PvP armor progression. Unlocks <b>epic helm, chest, and shoulders</b>, completing the 6-piece epic PvP set. These were endgame BiS for battleground and world PvP players, and a symbol of incredible time investment.', 3, 'PvP_R13', 1870, 1),
  (81, 'The Postmaster', 'world', 'Mage', 'The Postmaster', 'A quirky set from Stratholme mail couriers. Provided movement speed and bag space bonuses. Favored by <b>Mages</b> and <b>Priests</b> farming dungeons.', 5, 'WD_Postmaster', 1120, 1),
